<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Bouncing Ball Physics Playground</title>
<style>
  * { margin: 0; padding: 0; box-sizing: border-box; }
  body {
    background: #1a1a2e;
    color: #e0e0e0;
    font-family: 'Segoe UI', system-ui, sans-serif;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    min-height: 100vh;
    gap: 16px;
  }
  h1 {
    font-size: 1.4rem;
    color: #a0a0cc;
    letter-spacing: 1px;
    text-transform: uppercase;
  }
  #sim {
    border: 2px solid #3a3a5c;
    border-radius: 8px;
    cursor: crosshair;
    background: #0f0f1a;
    box-shadow: 0 0 30px rgba(80, 80, 160, 0.15);
  }
  .controls {
    display: flex;
    gap: 12px;
  }
  button {
    background: #2a2a4a;
    color: #c0c0e0;
    border: 1px solid #4a4a6a;
    padding: 10px 24px;
    border-radius: 6px;
    font-size: 0.95rem;
    cursor: pointer;
    transition: background 0.15s, transform 0.1s;
    user-select: none;
  }
  button:hover { background: #3a3a6a; }
  button:active { transform: scale(0.96); }
  #play.playing { background: #3a5a3a; border-color: #5a8a5a; }
  .info {
    font-size: 0.8rem;
    color: #666688;
  }
</style>
</head>
<body>

<h1>Bouncing Ball Playground</h1>
<canvas id="sim" width="600" height="500"></canvas>
<div class="controls">
  <button id="drop">Drop Ball</button>
  <button id="play">Play</button>
  <button id="clear">Clear</button>
</div>
<div class="info">Click the canvas to add balls</div>

<script>
(function() {
  const canvas = document.getElementById('sim');
  const ctx = canvas.getContext('2d');
  const W = canvas.width;
  const H = canvas.height;

  const GRAVITY = 500;       // pixels/s²
  const RESTITUTION = 0.75;  // energy kept on bounce
  const SUB_STEPS = 4;       // physics sub-steps per frame for stability

  let balls = [];
  let running = false;
  let animId = null;

  // Color palette for balls
  const COLORS = [
    '#ff6b6b', '#ffa94d', '#ffd43b', '#69db7c', '#38d9a9',
    '#4dabf7', '#748ffc', '#b197fc', '#e599f7', '#ff8787',
    '#63e6be', '#a9e34b', '#f59f00', '#00b4d8', '#e07a5f'
  ];

  function randomColor() {
    return COLORS[Math.floor(Math.random() * COLORS.length)];
  }

  function createBall(x, y, vx, vy, r) {
    return {
      x: x,
      y: y,
      vx: vx || 0,
      vy: vy || 0,
      r: r || (8 + Math.random() * 18),
      color: randomColor()
    };
  }

  function addBall(x, y, vx, vy, r) {
    const ball = createBall(x, y, vx, vy, r);
    balls.push(ball);
    return ball;
  }

  function clear() {
    balls = [];
    draw();
  }

  function ballsSnapshot() {
    return balls.map(b => ({ x: b.x, y: b.y, vx: b.vx, vy: b.vy, r: b.r }));
  }

  function physicsStep(dt) {
    const subDt = dt / SUB_STEPS;

    for (let s = 0; s < SUB_STEPS; s++) {
      for (let i = 0; i < balls.length; i++) {
        const b = balls[i];

        // Apply gravity
        b.vy += GRAVITY * subDt;

        // Update position
        b.x += b.vx * subDt;
        b.y += b.vy * subDt;

        // Bounce off left wall
        if (b.x - b.r < 0) {
          b.x = b.r;
          b.vx = -b.vx * RESTITUTION;
        }
        // Bounce off right wall
        if (b.x + b.r > W) {
          b.x = W - b.r;
          b.vx = -b.vx * RESTITUTION;
        }
        // Bounce off top wall
        if (b.y - b.r < 0) {
          b.y = b.r;
          b.vy = -b.vy * RESTITUTION;
        }
        // Bounce off bottom wall
        if (b.y + b.r > H) {
          b.y = H - b.r;
          b.vy = -b.vy * RESTITUTION;
        }
      }
    }
  }

  function draw() {
    ctx.clearRect(0, 0, W, H);

    // Draw subtle grid
    ctx.strokeStyle = 'rgba(255,255,255,0.03)';
    ctx.lineWidth = 1;
    for (let gx = 0; gx < W; gx += 40) {
      ctx.beginPath();
      ctx.moveTo(gx, 0);
      ctx.lineTo(gx, H);
      ctx.stroke();
    }
    for (let gy = 0; gy < H; gy += 40) {
      ctx.beginPath();
      ctx.moveTo(0, gy);
      ctx.lineTo(W, gy);
      ctx.stroke();
    }

    // Draw balls
    for (let i = 0; i < balls.length; i++) {
      const b = balls[i];

      // Glow
      ctx.beginPath();
      ctx.arc(b.x, b.y, b.r + 4, 0, Math.PI * 2);
      ctx.fillStyle = b.color + '30';
      ctx.fill();

      // Ball body
      ctx.beginPath();
      ctx.arc(b.x, b.y, b.r, 0, Math.PI * 2);
      ctx.fillStyle = b.color;
      ctx.fill();

      // Highlight
      ctx.beginPath();
      ctx.arc(b.x - b.r * 0.3, b.y - b.r * 0.3, b.r * 0.35, 0, Math.PI * 2);
      ctx.fillStyle = 'rgba(255,255,255,0.35)';
      ctx.fill();

      // Border
      ctx.beginPath();
      ctx.arc(b.x, b.y, b.r, 0, Math.PI * 2);
      ctx.strokeStyle = 'rgba(0,0,0,0.3)';
      ctx.lineWidth = 1.5;
      ctx.stroke();
    }
  }

  function step(dt) {
    dt = dt || 1;
    // dt is in "frames"; convert to seconds (assume 60fps)
    const dtSec = dt / 60;
    physicsStep(dtSec);
    draw();
  }

  function animate() {
    step(1);
    if (running) {
      animId = requestAnimationFrame(animate);
    }
  }

  function togglePlay() {
    running = !running;
    const btn = document.getElementById('play');
    if (running) {
      btn.textContent = 'Pause';
      btn.classList.add('playing');
      animate();
    } else {
      btn.textContent = 'Play';
      btn.classList.remove('playing');
      if (animId) cancelAnimationFrame(animId);
    }
  }

  // Canvas click handler
  canvas.addEventListener('click', function(e) {
    const rect = canvas.getBoundingClientRect();
    const scaleX = W / rect.width;
    const scaleY = H / rect.height;
    const x = (e.clientX - rect.left) * scaleX;
    const y = (e.clientY - rect.top) * scaleY;
    addBall(x, y, (Math.random() - 0.5) * 200, (Math.random() - 0.5) * 100);
    draw();
  });

  // Button handlers
  document.getElementById('drop').addEventListener('click', function() {
    const x = 50 + Math.random() * (W - 100);
    const y = 30 + Math.random() * 50;
    addBall(x, y, (Math.random() - 0.5) * 300, 0);
    draw();
  });

  document.getElementById('play').addEventListener('click', togglePlay);
  document.getElementById('clear').addEventListener('click', clear);

  // Initial draw
  draw();

  // Expose API
  window.sim = {
    w: W,
    h: H,
    balls: ballsSnapshot,
    addBall: addBall,
    clear: clear,
    step: step
  };
})();
</script>

</body>
</html>
